// @ts-check

const commentIdComment = '<!-- comment-id: metrics-report-action report -->'
const commentAdditionComment =
    "\n<!-- This is an autogenerated comment. Please don't alter the line above and don't include it in other comments. -->\n\n"

/**
 * Creates or updates the metrics report comment using caller-provided GitHub client adapters.
 *
 * @template T
 * @param {{
 *   body: string
 *   createComment: (body: string) => Promise<T>
 *   findCommentToUpdate: () => Promise<T | undefined>
 *   updateComment: (comment: T, body: string) => Promise<T>
 * }} options
 * @returns {Promise<{ action: 'created' | 'updated', comment: T }>}
 */
export async function setMetricsReportComment({
    body,
    createComment,
    findCommentToUpdate,
    updateComment,
}) {
    const wrappedBody = getMetricsReportCommentBody(body)
    const commentToUpdate = await findCommentToUpdate()

    if (commentToUpdate) {
        return {
            action: 'updated',
            comment: await updateComment(commentToUpdate, wrappedBody),
        }
    }

    return {
        action: 'created',
        comment: await createComment(wrappedBody),
    }
}

/**
 * @param {{ body?: string | null }} comment
 */
export function isMetricsReportComment(comment) {
    return comment.body?.startsWith(commentIdComment) ?? false
}

/**
 * @param {string} body
 */
function getMetricsReportCommentBody(body) {
    return commentIdComment + commentAdditionComment + body
}
